package com.example.bankapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        balanceTextView = findViewById(R.id.balanceTextView);
        updateBalance(1000.00); // Initial balance

        // Example transaction
        processTransaction(-50.00, "Withdrawal");
    }

    private void updateBalance(double newBalance) {
        balanceTextView.setText("Current Balance: $" + String.format("%.2f", newBalance));
    }

    private void processTransaction(double amount, String type) {
        double currentBalance = Double.parseDouble(balanceTextView.getText().toString().replace("Current Balance: $", ""));
        if (type.equals("Withdrawal") && amount > 0) {
            updateBalance(currentBalance - amount);
        } else if (type.equals("Deposit") && amount > 0) {
            updateBalance(currentBalance + amount);
        }
    }
}